// Recuperer les donnees du webhook
const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const automationCode = body.automationCode;
const automationNom = body.automationNom;
const folderName = body.folderName || 'Client';

// Nom du dossier dans n8n : "[Client] NomEntreprise"
const n8nFolderName = `[Client] ${folderName}`;

return [{
  json: {
    tenantId,
    automationCode,
    automationNom,
    folderName: n8nFolderName,
    originalFolderName: folderName
  }
}];

// Verifier si un dossier (project) existe deja pour ce client
const projects = $input.first().json.data || $input.first().json || [];
const folderName = $('02. Preparer donnees').first().json.folderName;

const existing = Array.isArray(projects) 
  ? projects.find(p => p.name === folderName)
  : null;

return [{
  json: {
    folderExists: !!existing,
    folderId: existing ? existing.id : null,
    folderName: folderName,
    tenantId: $('02. Preparer donnees').first().json.tenantId,
    automationCode: $('02. Preparer donnees').first().json.automationCode,
    automationNom: $('02. Preparer donnees').first().json.automationNom
  }
}];

// Recuperer l'ID du dossier (cree ou existant)
let folderId;
let folderName;

try {
  // Si on vient de creer le dossier
  const created = $('06. Creer dossier n8n').first();
  if (created) {
    folderId = created.json.id || created.json.data?.id;
    folderName = created.json.name || created.json.data?.name;
  }
} catch {
  // Dossier existait deja
  const existing = $('04. Verifier dossier existant').first();
  folderId = existing.json.folderId;
  folderName = existing.json.folderName;
}

const data = $('04. Verifier dossier existant').first().json;

return [{
  json: {
    folderId: folderId || data.folderId,
    folderName: folderName || data.folderName,
    tenantId: data.tenantId,
    automationCode: data.automationCode,
    automationNom: data.automationNom,
    workflowIds: []
  }
}];
